# Geometry helper functions module
# Provides utility functions for shape calculations

def calculate_perimeter_rectangle(width: float, height: float) -> float:
    return 2.0 * (width + height)

def calculate_diagonal_rectangle(width: float, height: float) -> float:
    # Pythagorean theorem
    return (width * width + height * height) ** 0.5

def format_dimensions(width: float, height: float) -> str:
    return f"{width} x {height}"

def scale_dimension(value: float, factor: float) -> float:
    return value * factor

def pi_constant() -> float:
    return 3.14159

def describe_circle_area(radius: float) -> str:
    area = pi_constant() * radius * radius
    return f"Circle area: {area}"

